프로젝트: D:\20. POC\TrmWordDict2 (Next.js 15 + Prisma 6, pnpm)
브랜치: yg_v0.2

Vitest + vitest-mock-extended 이미 설치됨. vitest.setup.ts에 prismaMock export됨.

**중요: 파일 작성 및 테스트 실행만. git commit 하지 말 것.**

## 작성할 파일들

### 1. `features/mcp-token/types.ts`

```typescript
export type McpTokenListItem = {
  id: bigint
  name: string
  createdAt: Date
  lastUsedAt: Date | null
  expiresAt: Date | null
  revokedAt: Date | null
}

export type IssueTokenInput = { name: string; expiresInDays?: number }
export type IssueTokenResult = { id: bigint; token: string }
```

### 2. `features/mcp-token/queries.ts`

```typescript
import { prisma } from '@/lib/prisma'
import { requireAuth } from '@/lib/auth'
import type { McpTokenListItem } from './types'

export async function listMyTokens(): Promise<McpTokenListItem[]> {
  const user = await requireAuth()
  return prisma.tbTrmMcpToken.findMany({
    where: { userId: user.id },
    select: { id: true, name: true, createdAt: true, lastUsedAt: true, expiresAt: true, revokedAt: true },
    orderBy: { createdAt: 'desc' },
  })
}
```

### 3. `features/mcp-token/actions.ts`

```typescript
'use server'
import { randomBytes, createHash } from 'crypto'
import { prisma } from '@/lib/prisma'
import { requireAuth } from '@/lib/auth'
import { revalidatePath } from 'next/cache'
import type { IssueTokenInput, IssueTokenResult } from './types'

export async function issueToken(input: IssueTokenInput): Promise<IssueTokenResult> {
  const user = await requireAuth()
  const raw = randomBytes(32).toString('hex')
  const token = `trmdict_pat_${raw}`
  const tokenHash = createHash('sha256').update(token).digest('hex')
  const expiresAt = input.expiresInDays
    ? new Date(Date.now() + input.expiresInDays * 86_400_000)
    : null
  const created = await prisma.tbTrmMcpToken.create({
    data: { tokenHash, name: input.name, userId: user.id, expiresAt },
  })
  revalidatePath('/admin/settings')
  return { id: created.id, token }
}

export async function revokeToken(id: bigint): Promise<void> {
  const user = await requireAuth()
  const owned = await prisma.tbTrmMcpToken.findFirst({ where: { id, userId: user.id } })
  if (!owned) throw new Error('Token not found')
  await prisma.tbTrmMcpToken.update({ where: { id }, data: { revokedAt: new Date() } })
  revalidatePath('/admin/settings')
}
```

### 4. `features/mcp-token/__tests__/actions.test.ts`

```typescript
import { describe, it, expect, vi } from 'vitest'
import { issueToken, revokeToken } from '../actions'
import { prismaMock } from '@/vitest.setup'

vi.mock('@/lib/auth', () => ({
  requireAuth: vi.fn().mockResolvedValue({ id: 'user-uuid-1', role: 'ADMIN' }),
}))
vi.mock('next/cache', () => ({ revalidatePath: vi.fn() }))

describe('issueToken', () => {
  it('generates trmdict_pat_ prefixed token and stores SHA-256 hash', async () => {
    prismaMock.tbTrmMcpToken.create.mockResolvedValue({ id: 1n } as any)
    const result = await issueToken({ name: 'my-laptop' })
    expect(result.token).toMatch(/^trmdict_pat_[a-f0-9]{64}$/)
    expect(prismaMock.tbTrmMcpToken.create).toHaveBeenCalledWith({
      data: expect.objectContaining({
        tokenHash: expect.stringMatching(/^[a-f0-9]{64}$/),
        userId: 'user-uuid-1',
        name: 'my-laptop',
      }),
    })
  })
})

describe('revokeToken', () => {
  it('sets revokedAt to now() for owned token', async () => {
    prismaMock.tbTrmMcpToken.findFirst.mockResolvedValue({ id: 5n, userId: 'user-uuid-1' } as any)
    prismaMock.tbTrmMcpToken.update.mockResolvedValue({} as any)
    await revokeToken(5n)
    expect(prismaMock.tbTrmMcpToken.update).toHaveBeenCalledWith({
      where: { id: 5n },
      data: { revokedAt: expect.any(Date) },
    })
  })

  it('throws when token not owned by current user', async () => {
    prismaMock.tbTrmMcpToken.findFirst.mockResolvedValue(null)
    await expect(revokeToken(99n)).rejects.toThrow('Token not found')
  })
})
```

### 5. `features/mcp-token/components/McpTokenList.tsx`

```tsx
import { listMyTokens } from '../queries'
import { revokeToken } from '../actions'
import { Button } from '@/components/ui/button'

export async function McpTokenList() {
  const tokens = await listMyTokens()
  return (
    <table className="w-full border-collapse text-sm">
      <thead>
        <tr className="border-b">
          <th className="text-left p-2">이름</th>
          <th className="text-left p-2">생성</th>
          <th className="text-left p-2">마지막 사용</th>
          <th className="text-left p-2">상태</th>
          <th className="text-left p-2">액션</th>
        </tr>
      </thead>
      <tbody>
        {tokens.map((t) => (
          <tr key={t.id.toString()} className="border-b">
            <td className="p-2 font-mono">{t.name}</td>
            <td className="p-2">{t.createdAt.toLocaleString('ko-KR')}</td>
            <td className="p-2">{t.lastUsedAt?.toLocaleString('ko-KR') ?? '-'}</td>
            <td className="p-2">
              {t.revokedAt ? 'revoked' : t.expiresAt && t.expiresAt < new Date() ? 'expired' : 'active'}
            </td>
            <td className="p-2">
              {!t.revokedAt && (
                <form action={async () => { 'use server'; await revokeToken(t.id) }}>
                  <Button type="submit" variant="destructive" size="sm">Revoke</Button>
                </form>
              )}
            </td>
          </tr>
        ))}
        {tokens.length === 0 && (
          <tr><td colSpan={5} className="p-4 text-center text-muted-foreground">발급된 PAT 없음</td></tr>
        )}
      </tbody>
    </table>
  )
}
```

### 6. `features/mcp-token/components/McpTokenIssueDialog.tsx`

```tsx
'use client'
import { useState } from 'react'
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger } from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { Input } from '@/components/ui/input'
import { issueToken } from '../actions'

export function McpTokenIssueDialog() {
  const [name, setName] = useState('')
  const [issued, setIssued] = useState<string | null>(null)
  const [open, setOpen] = useState(false)

  return (
    <Dialog open={open} onOpenChange={(v) => { setOpen(v); if (!v) { setName(''); setIssued(null) } }}>
      <DialogTrigger asChild>
        <Button>MCP PAT 발급</Button>
      </DialogTrigger>
      <DialogContent>
        <DialogHeader><DialogTitle>MCP Personal Access Token 발급</DialogTitle></DialogHeader>
        {issued ? (
          <div className="space-y-3">
            <p className="text-sm text-destructive font-medium">이 토큰은 다시 표시되지 않습니다. 즉시 복사하세요.</p>
            <code className="block break-all bg-muted p-3 rounded font-mono text-xs select-all">{issued}</code>
            <Button variant="outline" onClick={() => navigator.clipboard.writeText(issued)}>복사</Button>
          </div>
        ) : (
          <form
            onSubmit={async (e) => {
              e.preventDefault()
              const r = await issueToken({ name })
              setIssued(r.token)
            }}
            className="space-y-3"
          >
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="예: 회사 PC, 노트북"
              required
            />
            <Button type="submit" disabled={!name.trim()}>발급</Button>
          </form>
        )}
      </DialogContent>
    </Dialog>
  )
}
```

### 7. `app/(admin)/settings/page.tsx`

```tsx
import { McpTokenList } from '@/features/mcp-token/components/McpTokenList'
import { McpTokenIssueDialog } from '@/features/mcp-token/components/McpTokenIssueDialog'

export default function SettingsPage() {
  return (
    <div className="space-y-6 p-6">
      <header className="flex justify-between items-center">
        <div>
          <h1 className="text-2xl font-semibold">설정</h1>
          <p className="text-sm text-muted-foreground mt-1">MCP Personal Access Token 관리</p>
        </div>
        <McpTokenIssueDialog />
      </header>
      <McpTokenList />
    </div>
  )
}
```

## 실행

```bash
pnpm test features/mcp-token/__tests__/actions.test.ts
```

타입 에러가 있으면 수정. `requireAuth`의 반환 타입이 `lib/auth.ts`와 다를 수 있음. 실제 auth.ts에서 반환 타입을 확인 후 맞게 조정.

